import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './CustomerDashboard.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerMessages = () => {
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showNewMessage, setShowNewMessage] = useState(false);
  const [newMessage, setNewMessage] = useState({ subject: '', message: '' });

  useEffect(() => {
    fetchMessages();
  }, []);

  const fetchMessages = async () => {
    try {
      const response = await axios.get(`${API_URL}/messages`);
      setMessages(response.data.data || response.data);
    } catch (error) {
      console.error('Error fetching messages:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API_URL}/messages`, newMessage);
      setNewMessage({ subject: '', message: '' });
      setShowNewMessage(false);
      fetchMessages();
    } catch (error) {
      console.error('Error sending message:', error);
    }
  };

  if (loading) {
    return (
      <div className="main-content" style={{ marginLeft: 0, padding: '2rem' }}>
        <div className="loading">Loading...</div>
      </div>
    );
  }

  return (
    <div className="main-content" style={{ marginLeft: 0, padding: '2rem' }}>
      <div style={{ maxWidth: '800px', margin: '0 auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
          <h1 style={{ fontSize: '1.75rem', fontWeight: 600, color: '#212529' }}>Messages</h1>
          <button
            onClick={() => setShowNewMessage(!showNewMessage)}
            style={{
              padding: '0.75rem 1.5rem',
              background: '#212529',
              border: 'none',
              borderRadius: '4px',
              color: 'white',
              fontSize: '0.95rem',
              cursor: 'pointer'
            }}
          >
            {showNewMessage ? 'Cancel' : 'New Message'}
          </button>
        </div>

        {showNewMessage && (
          <div style={{ background: 'white', border: '1px solid #dee2e6', borderRadius: '8px', padding: '2rem', marginBottom: '2rem' }}>
            <h2 style={{ fontSize: '1.25rem', fontWeight: 600, marginBottom: '1.5rem', color: '#212529' }}>Send a Message</h2>
            <form onSubmit={handleSubmit}>
              <div style={{ marginBottom: '1.5rem' }}>
                <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 500, color: '#495057' }}>Subject</label>
                <input
                  type="text"
                  value={newMessage.subject}
                  onChange={(e) => setNewMessage({ ...newMessage, subject: e.target.value })}
                  style={{
                    width: '100%',
                    padding: '0.75rem',
                    border: '1px solid #ced4da',
                    borderRadius: '4px',
                    fontSize: '0.95rem'
                  }}
                  required
                />
              </div>
              <div style={{ marginBottom: '1.5rem' }}>
                <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 500, color: '#495057' }}>Message</label>
                <textarea
                  rows="4"
                  value={newMessage.message}
                  onChange={(e) => setNewMessage({ ...newMessage, message: e.target.value })}
                  style={{
                    width: '100%',
                    padding: '0.75rem',
                    border: '1px solid #ced4da',
                    borderRadius: '4px',
                    fontSize: '0.95rem',
                    resize: 'vertical'
                  }}
                  required
                />
              </div>
              <button
                type="submit"
                style={{
                  padding: '0.75rem 1.5rem',
                  background: '#212529',
                  border: 'none',
                  borderRadius: '4px',
                  color: 'white',
                  fontSize: '0.95rem',
                  cursor: 'pointer'
                }}
              >
                Send Message
              </button>
            </form>
          </div>
        )}

        {messages.length === 0 ? (
          <div style={{ background: 'white', border: '1px solid #dee2e6', borderRadius: '8px', padding: '3rem', textAlign: 'center', color: '#6c757d' }}>
            No messages yet.
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            {messages.map((msg) => (
              <div key={msg._id} style={{ background: 'white', border: '1px solid #dee2e6', borderRadius: '8px', padding: '1.5rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.5rem' }}>
                  <h3 style={{ fontSize: '1.1rem', fontWeight: 600, color: '#212529' }}>{msg.subject}</h3>
                  <span style={{
                    padding: '0.25rem 0.5rem',
                    background: msg.status === 'UNREAD' ? '#e9ecef' : '#f8f9fa',
                    borderRadius: '4px',
                    fontSize: '0.75rem',
                    color: '#495057'
                  }}>
                    {msg.status}
                  </span>
                </div>
                <p style={{ color: '#495057', marginBottom: '0.5rem', lineHeight: '1.6' }}>{msg.message}</p>
                <div style={{ fontSize: '0.85rem', color: '#6c757d' }}>
                  Sent: {new Date(msg.createdAt).toLocaleString()}
                </div>
                {msg.adminReply && (
                  <div style={{ marginTop: '1rem', padding: '1rem', background: '#f8f9fa', borderRadius: '4px' }}>
                    <p style={{ fontWeight: 500, marginBottom: '0.25rem', color: '#495057' }}>Admin Reply:</p>
                    <p style={{ color: '#6c757d' }}>{msg.adminReply}</p>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default CustomerMessages;
